(function($){'use strict';let mainChart=null;let sourceChart=null;let deviceChart=null;let realtimeInterval=null;function escapeHtml(string){return String(string).replace(/[&<>"']/g,function(s){return{'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[s];});}$(document).ready(function(){initTabs();initCharts();loadDashboardData(7);startRealtimePolling();$('.trackly-chart-filter-btn').on('click',function(){$('.trackly-chart-filter-btn').removeClass('active');$(this).addClass('active');const days=$(this).data('days');loadDashboardData(days);});});function initTabs(){$('.trackly-tab-btn').on('click',function(){const target=$(this).data('target');$('.trackly-tab-btn').removeClass('active');$('.trackly-tab-content').removeClass('active');$(this).addClass('active');$('#'+target).addClass('active');});}function initCharts(){const mainOptions={chart:{type:'area',height:350,toolbar:{show:false},zoom:{enabled:false},fontFamily:'Outfit,sans-serif',foreColor:'#64748b'},colors:['#8b5cf6','#06b6d4'],fill:{type:'gradient',gradient:{shadeIntensity:1,opacityFrom:0.45,opacityTo:0.05,stops:[0,100]}},dataLabels:{enabled:false},stroke:{curve:'smooth',width:3},series:[],xaxis:{categories:[]},noData:{text:'Loading...',align:'center',verticalAlign:'middle',style:{color:'#64748b',fontSize:'14px'}}};const sourceOptions={chart:{type:'donut',height:280,fontFamily:'Outfit,sans-serif'},colors:['#8b5cf6','#06b6d4','#10b981','#f43f5e','#e2e8f0'],series:[],labels:[],legend:{position:'bottom'},noData:{text:'Loading...'}};const deviceOptions={chart:{type:'donut',height:280,fontFamily:'Outfit,sans-serif'},colors:['#4f46e5','#06b6d4','#cbd5e1'],series:[],labels:[],legend:{position:'bottom'},noData:{text:'Loading...'}};mainChart=new ApexCharts(document.querySelector("#trackly-main-chart"),mainOptions);sourceChart=new ApexCharts(document.querySelector("#trackly-source-chart"),sourceOptions);deviceChart=new ApexCharts(document.querySelector("#trackly-device-chart"),deviceOptions);mainChart.render();sourceChart.render();deviceChart.render();}function loadDashboardData(days){$.ajax({url:tracklyData.rest_url+'/stats',method:'GET',data:{days:days},beforeSend:function(xhr){xhr.setRequestHeader('X-WP-Nonce',tracklyData.rest_nonce);},success:function(res){if(res.success){updateSummary(res.summary);updateMainChart(res.chart);updateSourceChart(res.sources);updateDeviceChart(res.devices);updatePagesTable(res.pages);updateRealtimeValue(res.realtime_users);}else{if(typeof tracklyData!=='undefined'&&tracklyData.debug){console.error('GA Data retrieval failed:',res.error);}}},error:function(err){if(typeof tracklyData!=='undefined'&&tracklyData.debug){console.error('AJAX Error:',err);}}});}function startRealtimePolling(){realtimeInterval=setInterval(function(){$.ajax({url:tracklyData.rest_url+'/realtime',method:'GET',beforeSend:function(xhr){xhr.setRequestHeader('X-WP-Nonce',tracklyData.rest_nonce);},success:function(res){if(res.success){updateRealtimeValue(res.realtime_users);}}});},20000);}function updateRealtimeValue(count){const $counter=$('#trackly-active-users');$counter.fadeOut(150,function(){$(this).text(count).fadeIn(150);});}function updateSummary(summaryData){if(!summaryData.rows||summaryData.rows.length===0)return;const metrics=summaryData.rows[0].metricValues;const views=parseInt(metrics[0].value).toLocaleString();const users=parseInt(metrics[1].value).toLocaleString();const bounce=(parseFloat(metrics[2].value)*100).toFixed(1)+'%';const durSec=parseInt(metrics[3].value);const mins=Math.floor(durSec/60);const secs=durSec % 60;const duration=mins+'d '+(secs<10 ? '0':'')+secs+'s';$('#trackly-stat-views').text(views);$('#trackly-stat-users').text(users);$('#trackly-stat-bounce').text(bounce);$('#trackly-stat-duration').text(duration);}function updateMainChart(chartData){const categories=[];const viewsSeries=[];const usersSeries=[];if(chartData.rows&&chartData.rows.length>0){chartData.rows.forEach(function(row){const rawDate=row.dimensionValues[0].value;const year=rawDate.substring(0,4);const month=rawDate.substring(4,6);const day=rawDate.substring(6,8);const dateObj=new Date(year,month-1,day);const formattedDate=dateObj.toLocaleDateString('en-US',{day:'numeric',month:'short'});categories.push(formattedDate);viewsSeries.push(parseInt(row.metricValues[0].value));usersSeries.push(parseInt(row.metricValues[1].value));});}mainChart.updateOptions({xaxis:{categories:categories}});mainChart.updateSeries([{name:'Pageviews',data:viewsSeries},{name:'Users',data:usersSeries}]);}function updateSourceChart(sourcesData){const series=[];const labels=[];if(sourcesData.rows&&sourcesData.rows.length>0){sourcesData.rows.forEach(function(row){labels.push(row.dimensionValues[0].value);series.push(parseInt(row.metricValues[0].value));});}sourceChart.updateOptions({labels:labels});sourceChart.updateSeries(series);}function updateDeviceChart(devicesData){const series=[];const labels=[];if(devicesData.rows&&devicesData.rows.length>0){devicesData.rows.forEach(function(row){const dev=row.dimensionValues[0].value;const translatedDev=dev==='desktop' ? 'Desktop':(dev==='mobile' ? 'Mobile':'Tablet');labels.push(translatedDev);series.push(parseInt(row.metricValues[0].value));});}deviceChart.updateOptions({labels:labels});deviceChart.updateSeries(series);}function updatePagesTable(pagesData){const $tbody=$('#trackly-pages-table tbody');$tbody.empty();if(!pagesData.rows||pagesData.rows.length===0){$tbody.append('<tr><td colspan="5" class="loading-td">No data found.</td></tr>');return;}pagesData.rows.forEach(function(row){const path=row.dimensionValues[0].value;const escPath=escapeHtml(path);const views=parseInt(row.metricValues[0].value).toLocaleString();const users=parseInt(row.metricValues[1].value).toLocaleString();const bounce=(parseFloat(row.metricValues[2].value)*100).toFixed(1)+'%';const durSec=parseInt(row.metricValues[3].value);const mins=Math.floor(durSec/60);const secs=durSec % 60;const duration=mins+':'+(secs<10 ? '0':'')+secs;const html=`<tr><td><a href="${escPath}" target="_blank" class="trackly-page-link"><code>${escPath}</code></a></td><td><strong>${views}</strong></td><td>${users}</td><td>${bounce}</td><td>${duration}</td></tr>`;$tbody.append(html);});}})(jQuery);